{% extends "base.html" %}

{% block content %}

<h2 class="text-center my-4 fw-bold">Add / Edit Food Item</h2>

<div class="container">
    <div class="row justify-content-center">
        <div class="col-12 col-md-8 col-lg-6">

            <div class="card shadow-sm border-0">
                <div class="card-body p-4">

                    <form action="" method="POST" enctype="multipart/form-data">
                        {% csrf_token %}

                        {% for field in spots_form %}
                            <div class="mb-3">
                                <label class="form-label fw-semibold">{{ field.label }}</label>

                                {{ field }}

                                {% if field.errors %}
                                    <div class="text-danger small">
                                        {{ field.errors }}
                                    </div>
                                {% endif %}
                            </div>
                        {% endfor %}

                        <div class="d-grid">
                            <button type="submit" class="btn btn-warning fw-bold py-2">
                                Save Food Item
                            </button>
                        </div>

                    </form>

                </div>
            </div>

        </div>
    </div>
</div>

{% endblock content %}


<style>
    form input, 
form select, 
form textarea {
    width: 100%;
    padding: 10px;
    border: 1px solid #ddd;
    border-radius: 8px;
    background: #fff;
}

form input:focus,
form select:focus,
form textarea:focus {
    border-color: #FFC900;
    box-shadow: 0 0 5px rgba(255, 201, 0, 0.5);
}
</style>
